import asyncio
import websockets
import json
import uuid
from datetime import datetime
from collections import defaultdict
from typing import Dict, Set, Optional, List
import logging

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)


class Item:
    def __init__(self, item_id: str, name: str, item_type: str, value: int, quantity: int = 1):
        self.item_id = item_id
        self.name = name
        self.item_type = item_type
        self.value = value
        self.quantity = quantity
    
    def to_dict(self):
        return {
            'item_id': self.item_id,
            'name': self.name,
            'type': self.item_type,
            'value': self.value,
            'quantity': self.quantity
        }


class Inventory:
    def __init__(self, max_slots: int = 50):
        self.items: Dict[str, Item] = {}
        self.max_slots = max_slots
        self.lock = asyncio.Lock()
    
    async def add_item(self, item: Item) -> bool:
        async with self.lock:
            if item.item_id in self.items:
                self.items[item.item_id].quantity += item.quantity
                return True
            elif len(self.items) < self.max_slots:
                self.items[item.item_id] = item
                return True
            return False
    
    async def remove_item(self, item_id: str, quantity: int = 1) -> Optional[Item]:
        async with self.lock:
            if item_id not in self.items:
                return None
            
            item = self.items[item_id]
            if item.quantity < quantity:
                return None
            
            if item.quantity == quantity:
                return self.items.pop(item_id)
            else:
                item.quantity -= quantity
                removed_item = Item(
                    item.item_id,
                    item.name,
                    item.item_type,
                    item.value,
                    quantity
                )
                return removed_item
    
    async def get_item(self, item_id: str) -> Optional[Item]:
        async with self.lock:
            return self.items.get(item_id)
    
    async def has_item(self, item_id: str, quantity: int = 1) -> bool:
        async with self.lock:
            if item_id not in self.items:
                return False
            return self.items[item_id].quantity >= quantity
    
    def to_dict(self):
        return {item_id: item.to_dict() for item_id, item in self.items.items()}


class TradeSession:
    def __init__(self, trade_id: str, player1_id: str, player2_id: str):
        self.trade_id = trade_id
        self.player1_id = player1_id
        self.player2_id = player2_id
        self.player1_items: List[tuple] = []
        self.player2_items: List[tuple] = []
        self.player1_ready = False
        self.player2_ready = False
        self.player1_confirmed = False
        self.player2_confirmed = False
        self.lock = asyncio.Lock()
        self.status = 'active'
        self.created_at = datetime.now()
    
    async def add_item(self, player_id: str, item_id: str, quantity: int) -> bool:
        async with self.lock:
            if self.status != 'active':
                return False
            
            if player_id == self.player1_id:
                self.player1_items.append((item_id, quantity))
                self.player1_ready = False
                self.player1_confirmed = False
                self.player2_ready = False
                self.player2_confirmed = False
                return True
            elif player_id == self.player2_id:
                self.player2_items.append((item_id, quantity))
                self.player1_ready = False
                self.player1_confirmed = False
                self.player2_ready = False
                self.player2_confirmed = False
                return True
            return False
    
    async def set_ready(self, player_id: str, ready: bool) -> bool:
        async with self.lock:
            if self.status != 'active':
                return False
            
            if player_id == self.player1_id:
                self.player1_ready = ready
                if not ready:
                    self.player1_confirmed = False
                    self.player2_confirmed = False
                return True
            elif player_id == self.player2_id:
                self.player2_ready = ready
                if not ready:
                    self.player1_confirmed = False
                    self.player2_confirmed = False
                return True
            return False
    
    async def confirm_trade(self, player_id: str) -> bool:
        async with self.lock:
            if self.status != 'active':
                return False
            
            if not self.player1_ready or not self.player2_ready:
                return False
            
            if player_id == self.player1_id:
                self.player1_confirmed = True
            elif player_id == self.player2_id:
                self.player2_confirmed = True
            else:
                return False
            
            return True
    
    async def is_confirmed(self) -> bool:
        async with self.lock:
            return self.player1_confirmed and self.player2_confirmed
    
    async def cancel(self):
        async with self.lock:
            self.status = 'cancelled'
    
    def to_dict(self):
        return {
            'trade_id': self.trade_id,
            'player1_id': self.player1_id,
            'player2_id': self.player2_id,
            'player1_items': self.player1_items,
            'player2_items': self.player2_items,
            'player1_ready': self.player1_ready,
            'player2_ready': self.player2_ready,
            'player1_confirmed': self.player1_confirmed,
            'player2_confirmed': self.player2_confirmed,
            'status': self.status
        }


class Player:
    def __init__(self, player_id: str, username: str, websocket):
        self.player_id = player_id
        self.username = username
        self.websocket = websocket
        self.inventory = Inventory()
        self.active_trade: Optional[str] = None
        self.lock = asyncio.Lock()
    
    async def send_message(self, message: dict):
        try:
            await self.websocket.send(json.dumps(message))
        except Exception as e:
            logger.error(f"Error sending message to {self.username}: {e}")


class GameServer:
    def __init__(self):
        self.players: Dict[str, Player] = {}
        self.websocket_to_player: Dict = {}
        self.trades: Dict[str, TradeSession] = {}
        self.global_lock = asyncio.Lock()
    
    async def register_player(self, websocket, username: str) -> Player:
        player_id = str(uuid.uuid4())
        player = Player(player_id, username, websocket)
        
        async with self.global_lock:
            self.players[player_id] = player
            self.websocket_to_player[websocket] = player_id
        
        await self.initialize_starter_items(player)
        
        logger.info(f"Player {username} ({player_id}) registered")
        return player
    
    async def initialize_starter_items(self, player: Player):
        starter_items = [
            Item(str(uuid.uuid4()), "Health Potion", "consumable", 50, 5),
            Item(str(uuid.uuid4()), "Iron Sword", "weapon", 100, 1),
            Item(str(uuid.uuid4()), "Gold Coins", "currency", 1, 100),
        ]
        
        for item in starter_items:
            await player.inventory.add_item(item)
    
    async def unregister_player(self, websocket):
        async with self.global_lock:
            if websocket in self.websocket_to_player:
                player_id = self.websocket_to_player[websocket]
                player = self.players.get(player_id)
                
                if player and player.active_trade:
                    await self.cancel_trade(player_id, player.active_trade)
                
                del self.websocket_to_player[websocket]
                if player_id in self.players:
                    del self.players[player_id]
                    logger.info(f"Player {player_id} unregistered")
    
    async def get_player(self, player_id: str) -> Optional[Player]:
        return self.players.get(player_id)
    
    async def initiate_trade(self, initiator_id: str, target_id: str) -> Optional[str]:
        initiator = await self.get_player(initiator_id)
        target = await self.get_player(target_id)
        
        if not initiator or not target:
            return None
        
        async with initiator.lock:
            if initiator.active_trade:
                return None
        
        async with target.lock:
            if target.active_trade:
                return None
        
        trade_id = str(uuid.uuid4())
        trade = TradeSession(trade_id, initiator_id, target_id)
        
        async with self.global_lock:
            self.trades[trade_id] = trade
        
        async with initiator.lock:
            initiator.active_trade = trade_id
        
        async with target.lock:
            target.active_trade = trade_id
        
        await initiator.send_message({
            'type': 'trade_initiated',
            'trade_id': trade_id,
            'with_player': target.username
        })
        
        await target.send_message({
            'type': 'trade_request',
            'trade_id': trade_id,
            'from_player': initiator.username
        })
        
        logger.info(f"Trade {trade_id} initiated between {initiator_id} and {target_id}")
        return trade_id
    
    async def add_trade_item(self, player_id: str, trade_id: str, item_id: str, quantity: int) -> bool:
        trade = self.trades.get(trade_id)
        if not trade:
            return False
        
        player = await self.get_player(player_id)
        if not player:
            return False
        
        if not await player.inventory.has_item(item_id, quantity):
            return False
        
        if await trade.add_item(player_id, item_id, quantity):
            await self.broadcast_trade_update(trade_id)
            return True
        
        return False
    
    async def set_trade_ready(self, player_id: str, trade_id: str, ready: bool) -> bool:
        trade = self.trades.get(trade_id)
        if not trade:
            return False
        
        if await trade.set_ready(player_id, ready):
            await self.broadcast_trade_update(trade_id)
            return True
        
        return False
    
    async def confirm_trade(self, player_id: str, trade_id: str) -> bool:
        trade = self.trades.get(trade_id)
        if not trade:
            return False
        
        if not await trade.confirm_trade(player_id):
            return False
        
        if await trade.is_confirmed():
            await self.execute_trade(trade_id)
            return True
        
        await self.broadcast_trade_update(trade_id)
        return True
    
    async def execute_trade(self, trade_id: str):
        trade = self.trades.get(trade_id)
        if not trade:
            return
        
        player1 = await self.get_player(trade.player1_id)
        player2 = await self.get_player(trade.player2_id)
        
        if not player1 or not player2:
            await self.cancel_trade(trade.player1_id, trade_id)
            return
        
        async with trade.lock:
            try:
                player1_items_to_transfer = []
                for item_id, quantity in trade.player1_items:
                    removed_item = await player1.inventory.remove_item(item_id, quantity)
                    if not removed_item:
                        raise Exception(f"Player1 missing item {item_id}")
                    player1_items_to_transfer.append(removed_item)
                
                player2_items_to_transfer = []
                for item_id, quantity in trade.player2_items:
                    removed_item = await player2.inventory.remove_item(item_id, quantity)
                    if not removed_item:
                        for item in player1_items_to_transfer:
                            await player1.inventory.add_item(item)
                        raise Exception(f"Player2 missing item {item_id}")
                    player2_items_to_transfer.append(removed_item)
                
                for item in player1_items_to_transfer:
                    await player2.inventory.add_item(item)
                
                for item in player2_items_to_transfer:
                    await player1.inventory.add_item(item)
                
                trade.status = 'completed'
                
                await player1.send_message({
                    'type': 'trade_completed',
                    'trade_id': trade_id,
                    'inventory': player1.inventory.to_dict()
                })
                
                await player2.send_message({
                    'type': 'trade_completed',
                    'trade_id': trade_id,
                    'inventory': player2.inventory.to_dict()
                })
                
                async with player1.lock:
                    player1.active_trade = None
                async with player2.lock:
                    player2.active_trade = None
                
                logger.info(f"Trade {trade_id} completed successfully")
                
            except Exception as e:
                logger.error(f"Error executing trade {trade_id}: {e}")
                await self.cancel_trade(trade.player1_id, trade_id)
    
    async def cancel_trade(self, player_id: str, trade_id: str):
        trade = self.trades.get(trade_id)
        if not trade:
            return
        
        await trade.cancel()
        
        player1 = await self.get_player(trade.player1_id)
        player2 = await self.get_player(trade.player2_id)
        
        if player1:
            async with player1.lock:
                player1.active_trade = None
            await player1.send_message({
                'type': 'trade_cancelled',
                'trade_id': trade_id
            })
        
        if player2:
            async with player2.lock:
                player2.active_trade = None
            await player2.send_message({
                'type': 'trade_cancelled',
                'trade_id': trade_id
            })
        
        async with self.global_lock:
            if trade_id in self.trades:
                del self.trades[trade_id]
        
        logger.info(f"Trade {trade_id} cancelled")
    
    async def broadcast_trade_update(self, trade_id: str):
        trade = self.trades.get(trade_id)
        if not trade:
            return
        
        player1 = await self.get_player(trade.player1_id)
        player2 = await self.get_player(trade.player2_id)
        
        trade_data = trade.to_dict()
        
        if player1:
            await player1.send_message({
                'type': 'trade_update',
                'trade': trade_data
            })
        
        if player2:
            await player2.send_message({
                'type': 'trade_update',
                'trade': trade_data
            })
    
    async def transfer_item(self, from_player_id: str, to_player_id: str, item_id: str, quantity: int) -> bool:
        from_player = await self.get_player(from_player_id)
        to_player = await self.get_player(to_player_id)
        
        if not from_player or not to_player:
            return False
        
        if from_player_id < to_player_id:
            lock1, lock2 = from_player.lock, to_player.lock
        else:
            lock1, lock2 = to_player.lock, from_player.lock
        
        async with lock1:
            async with lock2:
                removed_item = await from_player.inventory.remove_item(item_id, quantity)
                if not removed_item:
                    return False
                
                if not await to_player.inventory.add_item(removed_item):
                    await from_player.inventory.add_item(removed_item)
                    return False
        
        await from_player.send_message({
            'type': 'item_sent',
            'to_player': to_player.username,
            'item_id': item_id,
            'quantity': quantity,
            'inventory': from_player.inventory.to_dict()
        })
        
        await to_player.send_message({
            'type': 'item_received',
            'from_player': from_player.username,
            'item_id': item_id,
            'quantity': quantity,
            'inventory': to_player.inventory.to_dict()
        })
        
        logger.info(f"Item {item_id} x{quantity} transferred from {from_player_id} to {to_player_id}")
        return True
    
    async def handle_message(self, websocket, message: str):
        try:
            data = json.loads(message)
            msg_type = data.get('type')
            
            if websocket not in self.websocket_to_player:
                if msg_type == 'login':
                    username = data.get('username', f'Player_{uuid.uuid4().hex[:8]}')
                    player = await self.register_player(websocket, username)
                    await player.send_message({
                        'type': 'login_success',
                        'player_id': player.player_id,
                        'username': player.username,
                        'inventory': player.inventory.to_dict()
                    })
                return
            
            player_id = self.websocket_to_player[websocket]
            player = await self.get_player(player_id)
            
            if not player:
                return
            
            if msg_type == 'get_inventory':
                await player.send_message({
                    'type': 'inventory',
                    'inventory': player.inventory.to_dict()
                })
            
            elif msg_type == 'initiate_trade':
                target_id = data.get('target_player_id')
                trade_id = await self.initiate_trade(player_id, target_id)
                if not trade_id:
                    await player.send_message({
                        'type': 'error',
                        'message': 'Failed to initiate trade'
                    })
            
            elif msg_type == 'add_trade_item':
                trade_id = data.get('trade_id')
                item_id = data.get('item_id')
                quantity = data.get('quantity', 1)
                
                success = await self.add_trade_item(player_id, trade_id, item_id, quantity)
                if not success:
                    await player.send_message({
                        'type': 'error',
                        'message': 'Failed to add item to trade'
                    })
            
            elif msg_type == 'set_ready':
                trade_id = data.get('trade_id')
                ready = data.get('ready', False)
                
                await self.set_trade_ready(player_id, trade_id, ready)
            
            elif msg_type == 'confirm_trade':
                trade_id = data.get('trade_id')
                await self.confirm_trade(player_id, trade_id)
            
            elif msg_type == 'cancel_trade':
                trade_id = data.get('trade_id')
                await self.cancel_trade(player_id, trade_id)
            
            elif msg_type == 'transfer_item':
                target_id = data.get('target_player_id')
                item_id = data.get('item_id')
                quantity = data.get('quantity', 1)
                
                success = await self.transfer_item(player_id, target_id, item_id, quantity)
                if not success:
                    await player.send_message({
                        'type': 'error',
                        'message': 'Failed to transfer item'
                    })
            
            elif msg_type == 'list_players':
                players_list = []
                for pid, p in self.players.items():
                    if pid != player_id:
                        players_list.append({
                            'player_id': pid,
                            'username': p.username
                        })
                
                await player.send_message({
                    'type': 'players_list',
                    'players': players_list
                })
        
        except Exception as e:
            logger.error(f"Error handling message: {e}")
    
    async def handle_client(self, websocket, path):
        try:
            async for message in websocket:
                await self.handle_message(websocket, message)
        except websockets.exceptions.ConnectionClosed:
            logger.info("Client disconnected")
        finally:
            await self.unregister_player(websocket)


async def main():
    server = GameServer()
    
    async with websockets.serve(server.handle_client, "localhost", 8765):
        logger.info("Game server started on ws://localhost:8765")
        await asyncio.Future()


if __name__ == "__main__":
    asyncio.run(main())